#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld",&N);
        int pw=0;
        while((1LL<<(pw+1))<=N) ++pw; // floor(log2 N)
        long long ans=N-1-pw;
        printf("%lld\n",ans);
    }
    return 0;
}

